import { useLoaderData } from "react-router-dom";

import EventsList from "../components/EventsList";

function EventsPage() {
  const data = useLoaderData();

  //if (data.isError) {
  //  return <p>{data.message}</p>;
  //}

  const events = data.events;

  return (
    <>
      <EventsList events={events} />
    </>
  );
}

export default EventsPage;

export async function loader() {
  //in loader function u can use browser APIs but not react hooks
  const response = await fetch("http://localhost:8080/eventsewfwfewf");

  if (!response.ok) {
    //return { isError: true, message: "couldnt fetch events" };
    throw {message: 'couldnt fetch events'};
  } else {
    //const resData = await response.json();
    //return resData.events;
    return response;
  }
}
